/* CISSP :: content/quiz5.js — CISSP Domain 5 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
{ id:"D5-001", domain:5, obj:"5.1", diff:"easy", q:"A badge reader unlocks a data-center door only for employees whose cards are on the approved list. Which category of control does the badge reader represent?", options:["Administrative control","Detective control","Physical access control","Compensating control"], answer:2, explain:"<strong>Physical access control</strong> restricts entry to a physical space using mechanisms such as badge readers, locks, and turnstiles, which is exactly what the door reader does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Administrative control</b>: administrative controls are policies and procedures, not the physical mechanism enforcing the door.</span><span class='qd'><b>Detective control</b>: a detective control identifies events after the fact; the reader prevents entry rather than merely detecting it.</span><span class='qd'><b>Compensating control</b>: a compensating control substitutes for a primary control that cannot be met, which is not what a standard badge reader is.</span>" },
{ id:"D5-002", domain:5, obj:"5.1", diff:"medium", q:"A security manager wants a single choke point where all personnel entering a secure area are funneled past a guard one at a time, preventing tailgating. Which physical control BEST achieves this?", options:["Bollard","Faraday cage","Mantrap (access control vestibule)","Turnstile bypass gate"], answer:2, explain:"<strong>Mantrap (access control vestibule)</strong> is a small two-door space that permits only one authenticated person through at a time, directly preventing tailgating.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bollard</b>: a bollard blocks vehicles, not the single-person entry of people.</span><span class='qd'><b>Faraday cage</b>: a Faraday cage blocks electromagnetic emanations, not personnel tailgating.</span><span class='qd'><b>Turnstile bypass gate</b>: a bypass gate is the wide accessible lane and typically weakens single-person control rather than enforcing it.</span>" },
{ id:"D5-003", domain:5, obj:"5.1", diff:"easy", q:"Which principle dictates that a subject should be granted only the access rights necessary to perform its job and nothing more?", options:["Separation of duties","Defense in depth","Least privilege","Implicit allow"], answer:2, explain:"<strong>Least privilege</strong> grants a subject exactly the permissions required for its function and no more, limiting the damage from error or compromise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Separation of duties</b>: separation of duties splits a sensitive task among people; it is a related but distinct control from minimizing each subject's rights.</span><span class='qd'><b>Defense in depth</b>: defense in depth layers multiple controls and is not specifically about minimizing granted rights.</span><span class='qd'><b>Implicit allow</b>: implicit allow grants access by default, the opposite of least privilege.</span>" },
{ id:"D5-004", domain:5, obj:"5.1", diff:"medium", q:"A firewall rule base ends with a rule that blocks any traffic not explicitly permitted by an earlier rule. This final rule embodies which access-control philosophy?", options:["Need to know","Fail open","Discretionary access","Implicit deny"], answer:3, explain:"<strong>Implicit deny</strong> denies everything that is not expressly allowed, which is precisely the function of a default-deny final firewall rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fail open</b>: fail open grants access when a control fails, the opposite of denying by default.</span><span class='qd'><b>Discretionary access</b>: discretionary access lets owners set permissions and is not the default-deny concept.</span><span class='qd'><b>Need to know</b>: need to know restricts access to information required for a task, a related but different principle from a default-deny rule.</span>" },
{ id:"D5-005", domain:5, obj:"5.1", diff:"easy", q:"An organization separates the ability to request a new vendor from the ability to approve payment to that vendor so no single employee can create and pay a fraudulent vendor. This control is:", options:["Least privilege","Mandatory vacation","Separation of duties","Dual control of keys"], answer:2, explain:"<strong>Separation of duties</strong> divides a sensitive process into parts assigned to different people so that fraud requires collusion, exactly as splitting vendor creation from payment approval does.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege</b>: least privilege minimizes each subject's rights but does not by itself require multiple people to complete a process.</span><span class='qd'><b>Mandatory vacation</b>: mandatory vacation forces time off to surface hidden fraud, not the splitting of a single transaction.</span><span class='qd'><b>Dual control of keys</b>: dual control requires two people to perform one action together and is a narrower special case, not the segregation of distinct duties described.</span>" },
{ id:"D5-006", domain:5, obj:"5.1", diff:"hard", q:"A CISO must protect an unstaffed remote equipment shed. Guards are impractical, but management wants both to discourage intrusion and to capture evidence if it occurs. Which pairing BEST meets both goals?", options:["Bollards as detective and lighting as corrective","Encryption as preventive and hashing as detective","Firewall as deterrent and IDS as corrective","Warning signage as deterrent and CCTV as detective control"], answer:3, explain:"<strong>Warning signage as deterrent and CCTV as detective control</strong> matches the goals: signage discourages intrusion (deterrent) while cameras record evidence of any intrusion (detective).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption as preventive and hashing as detective</b>: these are logical data controls, irrelevant to protecting a physical shed.</span><span class='qd'><b>Firewall as deterrent and IDS as corrective</b>: firewalls and IDS are network controls, not physical site protection, and an IDS is detective, not corrective.</span><span class='qd'><b>Bollards as detective and lighting as corrective</b>: bollards are preventive and lighting is deterrent/detective; the control types are mislabeled.</span>" },
{ id:"D5-007", domain:5, obj:"5.1", diff:"easy", q:"An access control list (ACL) attached to a file specifies which users may read or write it. In access-control terms, the file is the:", options:["Subject","Rule","Object","Principal"], answer:2, explain:"<strong>Object</strong> is the passive resource being accessed, such as the file whose ACL lists permitted users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Subject</b>: the subject is the active entity (user or process) requesting access, not the file.</span><span class='qd'><b>Rule</b>: a rule is an entry that grants or denies access, not the resource itself.</span><span class='qd'><b>Principal</b>: a principal is the authenticated identity acting as a subject, again the active party rather than the file.</span>" },
{ id:"D5-008", domain:5, obj:"5.1", diff:"medium", q:"A company wants building access decisions logged, alarmed on forced entry, and reviewable later. Which combination of control functions is being requested?", options:["Preventive, deterrent, and directive","Physical, detective, and corrective only","Preventive, detective, and audit (recovery)","Compensating, deterrent, and administrative"], answer:2, explain:"<strong>Preventive, detective, and audit (recovery)</strong> maps to the request: the lock prevents entry, the alarm detects forced entry, and the reviewable log supports audit and after-the-fact recovery.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Preventive, deterrent, and directive</b>: directive controls are policy guidance and the request does not describe deterrence or guidance, but detection and logging.</span><span class='qd'><b>Physical, detective, and corrective only</b>: this omits the preventive door lock and mislabels logging as corrective.</span><span class='qd'><b>Compensating, deterrent, and administrative</b>: nothing indicates a compensating substitute or administrative policy in the described mechanisms.</span>" },
{ id:"D5-009", domain:5, obj:"5.1", diff:"hard", q:"A regulated firm cannot immediately deploy full disk encryption on a legacy server that a mandate requires. To satisfy the auditor in the interim, it restricts the server to an isolated VLAN with strict ACLs and heightened monitoring. This interim measure is BEST classified as a:", options:["Corrective control","Detective control","Compensating control","Directive control"], answer:2, explain:"<strong>Compensating control</strong> is an alternative safeguard put in place when the required primary control cannot yet be implemented, exactly like the VLAN isolation standing in for encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Corrective control</b>: a corrective control restores systems after an incident, not a substitute for a control that cannot be deployed.</span><span class='qd'><b>Detective control</b>: detection is only one part of the measure; the primary intent is to compensate for missing encryption.</span><span class='qd'><b>Directive control</b>: a directive control is guidance such as a policy, not a technical substitute safeguard.</span>" },
{ id:"D5-010", domain:5, obj:"5.1", diff:"easy", q:"Under the concept of need to know, a user who already has Secret clearance is denied access to a Secret project file because:", options:["Their clearance level is insufficient","The file is unclassified","They have no job requirement to see that specific file","Discretionary access always overrides clearance"], answer:2, explain:"<strong>They have no job requirement to see that specific file</strong> reflects need to know: clearance establishes eligibility, but access also requires a legitimate task-based reason for that particular information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Their clearance level is insufficient</b>: the user holds Secret clearance matching the file, so clearance is not the barrier.</span><span class='qd'><b>The file is unclassified</b>: the file is Secret, so classification level is not the issue.</span><span class='qd'><b>Discretionary access always overrides clearance</b>: in a need-to-know model access is not granted merely by owner discretion overriding the requirement.</span>" },
{ id:"D5-011", domain:5, obj:"5.1", diff:"easy", q:"Which of the following is an example of a logical (technical) access control rather than a physical one?", options:["A security guard at the lobby","A locked server-cabinet door","A password-protected login on a server","A perimeter fence"], answer:2, explain:"<strong>A password-protected login on a server</strong> is a logical/technical control implemented in software to govern access to a system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A security guard at the lobby</b>: a guard is a physical (and administrative) control, not a technical one.</span><span class='qd'><b>A locked server-cabinet door</b>: a lock is a physical control.</span><span class='qd'><b>A perimeter fence</b>: a fence is a physical barrier, not a logical control.</span>" },
{ id:"D5-012", domain:5, obj:"5.1", diff:"medium", q:"An organization enforces that highly sensitive systems can be administered only from a dedicated, hardened workstation that itself sits in a locked room. This layering of a physical control around a logical one BEST illustrates:", options:["Single point of failure","Fail-open design","Defense in depth","Privilege creep"], answer:2, explain:"<strong>Defense in depth</strong> layers multiple, diverse controls so that bypassing one still leaves others in place, as with a hardened admin workstation guarded by a physical lock.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single point of failure</b>: this describes a fragile design with one critical dependency, the opposite of layered defense.</span><span class='qd'><b>Fail-open design</b>: fail open grants access on failure and is unrelated to layering controls.</span><span class='qd'><b>Privilege creep</b>: privilege creep is the accumulation of unnecessary rights over time, not a layered-control design.</span>" },
{ id:"D5-013", domain:5, obj:"5.1", diff:"hard", q:"A manager insists that emergency responders be able to open all doors instantly during a fire, while the security team wants doors to stay locked against intruders. When resolving this tension, which safety principle takes precedence for life-safety egress?", options:["Doors should fail secure to block intruders","Doors should remain in their last state","Doors should fail safe (fail open) to protect human life","Doors should require dual authentication to open"], answer:2, explain:"<strong>Doors should fail safe (fail open) to protect human life</strong> is correct because life safety outweighs asset protection; egress doors must unlock on power or system failure so people can escape.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Doors should fail secure to block intruders</b>: fail secure can trap occupants and is inappropriate for life-safety egress paths.</span><span class='qd'><b>Doors should remain in their last state</b>: an ambiguous last state could leave egress locked, risking lives.</span><span class='qd'><b>Doors should require dual authentication to open</b>: adding authentication during a fire delays escape and endangers life.</span>" },
{ id:"D5-014", domain:5, obj:"5.1", diff:"medium", q:"To limit the blast radius if a service account is compromised, an architect scopes the account to a single database and read-only rights. Which two principles are being applied together?", options:["Separation of duties and mandatory vacation","Least privilege and defense in depth","Least privilege and need to know","Implicit allow and privilege escalation"], answer:2, explain:"<strong>Least privilege and need to know</strong> are applied: the account gets only the minimum rights (read-only) and only to the one database it must touch, restricting both permission scope and information scope.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Separation of duties and mandatory vacation</b>: neither dividing a task among people nor forced time off is depicted here.</span><span class='qd'><b>Least privilege and defense in depth</b>: least privilege applies, but scoping a single account is not layering multiple independent controls.</span><span class='qd'><b>Implicit allow and privilege escalation</b>: these describe over-permissioning, the opposite of the tight scoping shown.</span>" },
{ id:"D5-015", domain:5, obj:"5.2", diff:"easy", q:"In access control, the process of proving that a claimed identity truly belongs to the requester is called:", options:["Identification","Authorization","Authentication","Accounting"], answer:2, explain:"<strong>Authentication</strong> verifies that a subject is who it claims to be, typically by validating a credential such as a password, token, or biometric.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Identification</b>: identification is merely asserting an identity (e.g., typing a username), not proving it.</span><span class='qd'><b>Authorization</b>: authorization decides what an already-authenticated subject may do.</span><span class='qd'><b>Accounting</b>: accounting records what a subject did, not verification of identity.</span>" },
{ id:"D5-016", domain:5, obj:"5.2", diff:"easy", q:"Requiring a password plus a code from a hardware token combines which two authentication factor types?", options:["Something you know and something you have","Something you are and something you know","Something you have and somewhere you are","Something you do and something you are"], answer:0, explain:"<strong>Something you know and something you have</strong> is correct: a password is knowledge and a hardware token is a possession, so combining them uses two distinct factor categories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you are and something you know</b>: a token is not a biometric (something you are).</span><span class='qd'><b>Something you have and somewhere you are</b>: no location factor is used, only a password.</span><span class='qd'><b>Something you do and something you are</b>: neither a behavioral action nor a biometric is involved.</span>" },
{ id:"D5-017", domain:5, obj:"5.2", diff:"medium", q:"A system that already requires a password now also demands a fingerprint. Adding the fingerprint upgrades the login to multifactor because a fingerprint is:", options:["Something you know","Something you have","Something you are","Somewhere you are"], answer:2, explain:"<strong>Something you are</strong> describes a biometric such as a fingerprint, adding an inherence factor distinct from the knowledge-based password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you know</b>: knowledge factors are secrets like passwords or PINs, not physiological traits.</span><span class='qd'><b>Something you have</b>: possession factors are tokens or smart cards, not a fingerprint.</span><span class='qd'><b>Somewhere you are</b>: location factors are based on geolocation, not biometrics.</span>" },
{ id:"D5-018", domain:5, obj:"5.2", diff:"medium", q:"A login flow requires a password and a one-time code sent by SMS. A security architect argues this is weaker than a hardware authenticator app because SMS codes:", options:["Are a third authentication factor","Count as something you are","Can be intercepted via SIM swapping or SS7 attacks","Provide non-repudiation by default"], answer:2, explain:"<strong>Can be intercepted via SIM swapping or SS7 attacks</strong> is why SMS OTPs are considered weaker: the delivery channel can be hijacked, undermining the possession factor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Are a third authentication factor</b>: an SMS code is still a possession factor, not an additional category, and adding it does not make three factors.</span><span class='qd'><b>Count as something you are</b>: an SMS code is not a biometric.</span><span class='qd'><b>Provide non-repudiation by default</b>: SMS OTPs do not inherently provide non-repudiation and their weakness is interception, not repudiation.</span>" },
{ id:"D5-019", domain:5, obj:"5.2", diff:"medium", q:"A biometric access system is tuned so tightly that many legitimate employees are wrongly rejected. This increase describes a rise in the:", options:["False acceptance rate (FAR)","Crossover error rate (CER)","False rejection rate (FRR)","Enrollment rate"], answer:2, explain:"<strong>False rejection rate (FRR)</strong>, or Type I error, measures how often valid users are wrongly denied, which rises when a system's sensitivity is set too high.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>False acceptance rate (FAR)</b>: FAR (Type II) counts impostors wrongly accepted, which typically decreases when the system is made stricter.</span><span class='qd'><b>Crossover error rate (CER)</b>: CER is the single point where FAR equals FRR, not a rate that changes as described.</span><span class='qd'><b>Enrollment rate</b>: enrollment rate concerns registration speed, not authentication errors.</span>" },
{ id:"D5-020", domain:5, obj:"5.2", diff:"medium", q:"A vendor claims biometric device A has a lower crossover error rate (CER) than device B. Which statement about CER is correct?", options:["A lower CER indicates a generally more accurate biometric system","A higher CER is always better because it accepts more users","CER is the rate of enrollment failures","CER measures how fast the sensor reads a fingerprint"], answer:0, explain:"<strong>A lower CER indicates a generally more accurate biometric system</strong> because the crossover error rate is the point where FAR equals FRR, and a smaller value means fewer errors of both kinds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A higher CER is always better because it accepts more users</b>: a higher CER means more total errors, which is worse.</span><span class='qd'><b>CER is the rate of enrollment failures</b>: CER is about matching errors, not enrollment.</span><span class='qd'><b>CER measures how fast the sensor reads a fingerprint</b>: CER measures accuracy, not speed or throughput.</span>" },
{ id:"D5-021", domain:5, obj:"5.2", diff:"hard", q:"A bank's fingerprint reader is guarding a high-value vault. Management asks whether to bias the tuning toward lower FAR or lower FRR. For maximum security against impostors, the reader should be tuned to minimize:", options:["FRR, accepting more legitimate-user rejections","CER, which eliminates both error types","FAR, accepting more legitimate-user rejections","Throughput, to slow attackers"], answer:2, explain:"<strong>FAR, accepting more legitimate-user rejections</strong> is correct: to keep impostors out of a high-value vault you minimize false acceptance, which unavoidably raises false rejections of valid users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FRR, accepting more legitimate-user rejections</b>: minimizing FRR makes the system more permissive, admitting more impostors, the wrong bias for high security.</span><span class='qd'><b>CER, which eliminates both error types</b>: CER is a fixed comparison point and cannot be minimized to zero; tuning trades FAR against FRR.</span><span class='qd'><b>Throughput, to slow attackers</b>: throughput is a performance metric, not a security-accuracy tuning target.</span>" },
{ id:"D5-022", domain:5, obj:"5.2", diff:"easy", q:"A one-time password token generates a new 6-digit code every 30 seconds based on the current time and a shared secret. This is an example of a:", options:["HOTP (HMAC-based) token","Static password","TOTP (time-based) token","Challenge-response smart card"], answer:2, explain:"<strong>TOTP (time-based) token</strong> derives each code from the current time plus a shared secret, producing a fresh value on a fixed interval such as every 30 seconds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HOTP (HMAC-based) token</b>: HOTP advances by an event counter, not by time, so it does not roll every 30 seconds automatically.</span><span class='qd'><b>Static password</b>: a static password never changes, unlike a rotating one-time code.</span><span class='qd'><b>Challenge-response smart card</b>: challenge-response requires a server-issued challenge rather than a time-driven interval.</span>" },
{ id:"D5-023", domain:5, obj:"5.2", diff:"easy", q:"Which of the following is the WEAKEST form of authentication on its own?", options:["A reusable static password","A hardware security key","A fingerprint plus PIN","A smart card with certificate"], answer:0, explain:"<strong>A reusable static password</strong> is the weakest because it is a single knowledge factor that can be guessed, phished, reused, or stolen without the attacker needing anything physical.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hardware security key</b>: a hardware key is a possession factor resistant to phishing, far stronger than a password.</span><span class='qd'><b>A fingerprint plus PIN</b>: this combines two factors and is multifactor, stronger than a lone password.</span><span class='qd'><b>A smart card with certificate</b>: certificate-based smart cards are cryptographically strong possession factors.</span>" },
{ id:"D5-024", domain:5, obj:"5.2", diff:"hard", q:"An architect notes that combining two credentials of the same category, such as a password and a security question, does not truly increase assurance the way multifactor does. The core reason is that both are:", options:["Something you have","Something you are","Something you know","Somewhere you are"], answer:2, explain:"<strong>Something you know</strong> is correct: passwords and security-question answers are both knowledge factors, so stacking them keeps a single point of failure (memorized secrets that can be phished or guessed).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you have</b>: neither a password nor a security answer is a physical possession.</span><span class='qd'><b>Something you are</b>: neither is a biometric trait.</span><span class='qd'><b>Somewhere you are</b>: neither depends on the user's location.</span>" },
{ id:"D5-025", domain:5, obj:"5.2", diff:"easy", q:"During biometric enrollment, the system captures a user's trait and stores a mathematical representation for later comparison. This stored representation is called a:", options:["Reference template","Salt","Nonce","Ticket-granting ticket"], answer:0, explain:"<strong>Reference template</strong> is the stored mathematical model of a user's biometric, against which live samples are matched during authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Salt</b>: a salt is random data added before hashing passwords, not a biometric model.</span><span class='qd'><b>Nonce</b>: a nonce is a one-time value used to prevent replay, not a stored biometric.</span><span class='qd'><b>Ticket-granting ticket</b>: a TGT is a Kerberos credential, unrelated to biometric enrollment.</span>" },
{ id:"D5-026", domain:5, obj:"5.2", diff:"medium", q:"A CISO rejects storing user passwords in plaintext and mandates that each be salted and hashed. The PRIMARY benefit of adding a unique salt per password is that it:", options:["Encrypts the password so it can be decrypted later","Guarantees the password is complex","Defeats precomputed rainbow-table attacks","Provides multifactor authentication"], answer:2, explain:"<strong>Defeats precomputed rainbow-table attacks</strong> is the key benefit: a unique salt makes each hash distinct so attackers cannot reuse precomputed tables against many accounts at once.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypts the password so it can be decrypted later</b>: hashing is one-way; salting does not enable decryption.</span><span class='qd'><b>Guarantees the password is complex</b>: a salt does not affect the user's chosen password strength.</span><span class='qd'><b>Provides multifactor authentication</b>: salting is a storage protection, not an added authentication factor.</span>" },
{ id:"D5-027", domain:5, obj:"5.2", diff:"easy", q:"Single sign-on (SSO) primarily improves the user experience by allowing a user to:", options:["Use one authentication to access many systems","Bypass authorization checks entirely","Encrypt all network traffic automatically","Eliminate the need for any passwords"], answer:0, explain:"<strong>Use one authentication to access many systems</strong> is the essence of SSO: after authenticating once, the user gains access to multiple applications without re-entering credentials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bypass authorization checks entirely</b>: SSO handles authentication; each application still enforces its own authorization.</span><span class='qd'><b>Encrypt all network traffic automatically</b>: SSO is about identity, not blanket traffic encryption.</span><span class='qd'><b>Eliminate the need for any passwords</b>: SSO usually still relies on at least one credential to authenticate initially.</span>" },
{ id:"D5-028", domain:5, obj:"5.2", diff:"hard", q:"A risk manager warns that single sign-on, while convenient, introduces a specific downside that must be mitigated. Which statement BEST captures that downside and its mitigation?", options:["SSO weakens usability; mitigate with more passwords","SSO removes all authorization; mitigate by disabling logging","A compromised SSO credential can unlock many systems; mitigate by protecting it with strong MFA","SSO always violates least privilege; mitigate by deleting the IdP"], answer:2, explain:"<strong>A compromised SSO credential can unlock many systems; mitigate by protecting it with strong MFA</strong> is correct: SSO concentrates risk in one credential, so hardening that login with multifactor authentication reduces the exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SSO weakens usability; mitigate with more passwords</b>: SSO improves usability, and adding passwords defeats its purpose.</span><span class='qd'><b>SSO removes all authorization; mitigate by disabling logging</b>: SSO does not remove authorization, and disabling logging harms security.</span><span class='qd'><b>SSO always violates least privilege; mitigate by deleting the IdP</b>: SSO does not inherently violate least privilege, and removing the identity provider defeats SSO.</span>" },
{ id:"D5-029", domain:5, obj:"5.5", diff:"medium", q:"A password policy requires users to change passwords every 90 days, but analysts observe users making trivial changes and reusing old ones. Modern guidance (e.g., NIST SP 800-63B) suggests that forced periodic expiration:", options:["Is the single strongest control and should be shortened to 30 days","Prevents all credential stuffing","Eliminates the need for MFA","Often reduces security by encouraging weak, predictable changes"], answer:3, explain:"<strong>Often reduces security by encouraging weak, predictable changes</strong> reflects current guidance: mandatory frequent expiration drives users toward guessable patterns, so change is better triggered by evidence of compromise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Is the single strongest control and should be shortened to 30 days</b>: shortening intervals worsens the predictable-change behavior and is not the strongest control.</span><span class='qd'><b>Eliminates the need for MFA</b>: expiration policy does not replace multifactor authentication.</span><span class='qd'><b>Prevents all credential stuffing</b>: expiration does not stop stuffing attacks that use already-valid stolen credentials.</span>" },
{ id:"D5-030", domain:5, obj:"5.2", diff:"easy", q:"An attacker takes a large list of username/password pairs leaked from one site and tries them against a different site's login. This attack, which succeeds because users reuse passwords, is called:", options:["Credential stuffing","Privilege escalation","Session fixation","Cross-site scripting"], answer:0, explain:"<strong>Credential stuffing</strong> automates the reuse of stolen credential pairs against other services, exploiting password reuse across sites.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Privilege escalation</b>: escalation gains higher rights after access, not the mass reuse of leaked logins.</span><span class='qd'><b>Session fixation</b>: session fixation forces a known session id on a victim, not credential reuse.</span><span class='qd'><b>Cross-site scripting</b>: XSS injects script into web pages and is unrelated to reusing leaked credential lists.</span>" },
{ id:"D5-031", domain:5, obj:"5.2", diff:"hard", q:"A financial app wants passwordless login resistant to phishing. It adopts FIDO2/WebAuthn with device-bound keys. The PRIMARY reason this resists phishing better than OTP codes is that:", options:["The private key never leaves the authenticator and is bound to the site's origin","Users memorize a longer password","OTP codes are encrypted end to end","It disables all cookies"], answer:0, explain:"<strong>The private key never leaves the authenticator and is bound to the site's origin</strong> is why FIDO2/WebAuthn resists phishing: the credential only signs challenges for the legitimate origin, so a fake site cannot harvest anything reusable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Users memorize a longer password</b>: WebAuthn is passwordless; memorization is not the mechanism.</span><span class='qd'><b>OTP codes are encrypted end to end</b>: the scenario replaces OTPs, and OTPs can still be phished even if transmitted securely.</span><span class='qd'><b>It disables all cookies</b>: cookie handling is not what provides phishing resistance here.</span>" },
{ id:"D5-032", domain:5, obj:"5.5", diff:"medium", q:"A help desk resets a locked-out user's password only after the caller answers pre-registered security questions. In identity terms, this verification step during account recovery is a form of:", options:["Authorization","Federation","Accounting","Identity proofing/verification"], answer:3, explain:"<strong>Identity proofing/verification</strong> re-establishes that the caller is the legitimate account owner before recovery, using knowledge the true owner should possess.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authorization</b>: authorization determines allowed actions after identity is confirmed, not the confirmation itself.</span><span class='qd'><b>Accounting</b>: accounting logs activity; it does not verify the caller's identity.</span><span class='qd'><b>Federation</b>: federation shares identity across domains, not a help-desk verification step.</span>" },
{ id:"D5-033", domain:5, obj:"5.2", diff:"easy", q:"Which factor category does a smart card belong to?", options:["Something you know","Something you do","Something you are","Something you have"], answer:3, explain:"<strong>Something you have</strong> is correct because a smart card is a physical possession the user must present to authenticate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you know</b>: knowledge factors are secrets like PINs, though a card is often paired with one, the card itself is a possession.</span><span class='qd'><b>Something you are</b>: a smart card is not a biometric.</span><span class='qd'><b>Something you do</b>: behavioral factors involve actions like typing rhythm, not carrying a card.</span>" },
{ id:"D5-034", domain:5, obj:"5.2", diff:"medium", q:"A behavioral biometric system authenticates users by their unique typing cadence and mouse-movement patterns. This factor is BEST categorized as:", options:["Something you have","Something you are","Something you do","Somewhere you are"], answer:2, explain:"<strong>Something you do</strong> describes behavioral biometrics such as keystroke dynamics and mouse patterns, which measure how a person performs an action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you have</b>: no physical token is involved.</span><span class='qd'><b>Something you are</b>: physiological biometrics measure static traits (fingerprint, iris), whereas typing cadence is a behavior.</span><span class='qd'><b>Somewhere you are</b>: this is a location factor, not a behavioral one.</span>" },
{ id:"D5-035", domain:5, obj:"5.2", diff:"hard", q:"A conditional-access policy blocks a login when the request originates from a country where the user has never operated, even though the correct password and OTP were supplied. Which factor is the policy adding to the decision?", options:["Something you know","Something you have","Somewhere you are","Something you are"], answer:2, explain:"<strong>Somewhere you are</strong> is the location (geolocation/geovelocity) factor the policy evaluates, denying access from an implausible place despite valid credentials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you know</b>: the password (knowledge) was already provided and is not the added factor.</span><span class='qd'><b>Something you have</b>: the OTP (possession) was already provided; the new signal is location.</span><span class='qd'><b>Something you are</b>: no biometric was involved in the block.</span>" },
{ id:"D5-036", domain:5, obj:"5.2", diff:"medium", q:"A CISO wants authentication that is both convenient and strong, so users tap a phone prompt to approve logins. To prevent 'MFA fatigue' attacks where users blindly approve spam prompts, the BEST enhancement is:", options:["Send more prompts faster","Disable MFA during business hours","Switch to SMS-only codes","Add number matching so the user must enter a code shown on the login screen"], answer:3, explain:"<strong>Add number matching so the user must enter a code shown on the login screen</strong> defeats push-bombing because a user cannot approve blindly; they must transcribe a value they only see on the legitimate login.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send more prompts faster</b>: more prompts worsen fatigue and make accidental approval likelier.</span><span class='qd'><b>Switch to SMS-only codes</b>: SMS is weaker and still phishable, not an improvement.</span><span class='qd'><b>Disable MFA during business hours</b>: disabling MFA removes protection entirely.</span>" },
{ id:"D5-037", domain:5, obj:"5.2", diff:"easy", q:"Which statement correctly distinguishes identification from authentication?", options:["Identification proves the credential; authentication merely claims an identity","Authentication happens before identification","They are identical steps performed together","Identification claims an identity; authentication proves that claim"], answer:3, explain:"<strong>Identification claims an identity; authentication proves that claim</strong> correctly orders the two: a subject first asserts who it is, then supplies evidence to validate that assertion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Identification proves the credential; authentication merely claims an identity</b>: this reverses the roles of the two steps.</span><span class='qd'><b>They are identical steps performed together</b>: they are distinct phases with different purposes.</span><span class='qd'><b>Authentication happens before identification</b>: you must claim an identity before it can be verified.</span>" },
{ id:"D5-038", domain:5, obj:"5.2", diff:"hard", q:"A system stores biometric templates centrally. A privacy officer flags that, unlike a password, a compromised fingerprint template poses a unique lasting risk because:", options:["Fingerprints can be reset like passwords","Biometrics never need protection","Templates are always encrypted so there is no risk","Biometrics are non-revocable; you cannot issue a person a new fingerprint"], answer:3, explain:"<strong>Biometrics are non-revocable; you cannot issue a person a new fingerprint</strong> is the core concern: once a biometric is stolen, the underlying trait cannot be changed, so the exposure is permanent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fingerprints can be reset like passwords</b>: they cannot; that is precisely the problem.</span><span class='qd'><b>Templates are always encrypted so there is no risk</b>: encryption reduces but does not eliminate risk, and templates are not always encrypted.</span><span class='qd'><b>Biometrics never need protection</b>: biometric data is highly sensitive and requires strong protection.</span>" },
{ id:"D5-039", domain:5, obj:"5.5", diff:"medium", q:"An organization enrolls users into MFA. To balance security and usability for low-risk internal apps while enforcing MFA for sensitive ones, it uses policies that step up authentication based on risk. This approach is called:", options:["Static authentication","Anonymous authentication","Mutual TLS only","Adaptive (risk-based) authentication"], answer:3, explain:"<strong>Adaptive (risk-based) authentication</strong> varies the authentication requirements according to contextual risk, prompting for stronger proof only when the situation warrants it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static authentication</b>: static schemes apply the same requirement regardless of risk, the opposite of adaptive.</span><span class='qd'><b>Mutual TLS only</b>: mutual TLS authenticates endpoints with certificates but is not a risk-based step-up policy.</span><span class='qd'><b>Anonymous authentication</b>: anonymous access identifies no one and provides no risk-based control.</span>" },
{ id:"D5-040", domain:5, obj:"5.2", diff:"easy", q:"Which pillar of AAA is responsible for tracking and logging what an authenticated user actually does?", options:["Authentication","Authorization","Accounting","Attestation"], answer:2, explain:"<strong>Accounting</strong> records the actions and resource usage of authenticated subjects, providing the audit trail in the AAA model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authentication</b>: authentication verifies identity, not activity logging.</span><span class='qd'><b>Authorization</b>: authorization decides permitted actions, not the recording of them.</span><span class='qd'><b>Attestation</b>: attestation asserts the integrity/state of a device and is not one of the AAA pillars for logging.</span>" },
{ id:"D5-041", domain:5, obj:"5.5", diff:"hard", q:"A cloud IAM design must let a workload authenticate to an API without any embedded static secret that could leak. The BEST modern approach is to:", options:["Hard-code an API key in the source repository","Use a shared account for all services","Email the password to developers","Use short-lived tokens issued to a managed workload identity"], answer:3, explain:"<strong>Use short-lived tokens issued to a managed workload identity</strong> avoids embedded secrets: the platform mints ephemeral credentials for the workload, so nothing long-lived can leak.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hard-code an API key in the source repository</b>: committing secrets to source is a classic leak vector, exactly what must be avoided.</span><span class='qd'><b>Email the password to developers</b>: emailing credentials spreads and exposes the secret.</span><span class='qd'><b>Use a shared account for all services</b>: shared accounts destroy accountability and widen blast radius.</span>" },
{ id:"D5-042", domain:5, obj:"5.2", diff:"medium", q:"A user proves possession of a private key by signing a server-issued random challenge, which the server verifies with the matching public key. This authentication method is:", options:["Symmetric password comparison","Kerberos delegation","Rainbow-table lookup","Asymmetric challenge-response authentication"], answer:3, explain:"<strong>Asymmetric challenge-response authentication</strong> has the client sign a random challenge with its private key so the server can verify it with the public key, proving possession without sending the secret.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Symmetric password comparison</b>: comparing a shared password does not involve public/private key pairs or a challenge signature.</span><span class='qd'><b>Rainbow-table lookup</b>: rainbow tables are an attack technique, not an authentication method.</span><span class='qd'><b>Kerberos delegation</b>: delegation forwards a user's authority to a service and is a distinct Kerberos feature, not a public-key challenge signature.</span>" },
{ id:"D5-043", domain:5, obj:"5.3", diff:"easy", q:"Which XML-based standard is most commonly used to exchange authentication and authorization assertions between an identity provider and a service provider in enterprise SSO?", options:["SAML","OAuth 2.0","RADIUS","LDAP"], answer:0, explain:"<strong>SAML</strong> (Security Assertion Markup Language) is the XML standard that passes authentication and authorization assertions from an identity provider to a service provider for web SSO.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>OAuth 2.0</b>: OAuth is a delegated-authorization framework, and it is JSON/token-based rather than an XML assertion standard for SSO authentication.</span><span class='qd'><b>RADIUS</b>: RADIUS is a network AAA protocol, not an XML SSO assertion format.</span><span class='qd'><b>LDAP</b>: LDAP is a directory-access protocol, not a cross-domain SSO assertion standard.</span>" },
{ id:"D5-044", domain:5, obj:"5.3", diff:"easy", q:"In a SAML web SSO flow, which party generates the signed assertion vouching that the user has authenticated?", options:["The service provider (SP)","The certificate authority","The user's browser","The identity provider (IdP)"], answer:3, explain:"<strong>The identity provider (IdP)</strong> authenticates the user and issues the signed SAML assertion that the service provider then consumes to grant access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The service provider (SP)</b>: the SP relies on and validates the assertion; it does not generate it.</span><span class='qd'><b>The user's browser</b>: the browser merely relays the assertion between IdP and SP.</span><span class='qd'><b>The certificate authority</b>: the CA issues certificates used to sign, but it does not create the SAML assertion.</span>" },
{ id:"D5-045", domain:5, obj:"5.3", diff:"medium", q:"A developer needs to let a third-party app read a user's calendar without ever handling the user's password. Which framework is designed for this delegated authorization?", options:["OAuth 2.0","Kerberos","TACACS+","802.1X"], answer:0, explain:"<strong>OAuth 2.0</strong> lets a user grant a third-party application scoped access to resources via access tokens, so the app never sees the user's password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Kerberos</b>: Kerberos is an intra-domain authentication protocol using tickets, not third-party delegated authorization to web APIs.</span><span class='qd'><b>TACACS+</b>: TACACS+ is a network device AAA protocol, not an API delegation framework.</span><span class='qd'><b>802.1X</b>: 802.1X is port-based network access control, unrelated to delegating API access.</span>" },
{ id:"D5-046", domain:5, obj:"5.3", diff:"hard", q:"An engineer confuses OAuth 2.0 with authentication. The BEST correction is that OAuth 2.0 is fundamentally an authorization framework, and to obtain verified user identity on top of it you should use:", options:["OpenID Connect (OIDC)","SAML metadata","RADIUS accounting","Basic authentication"], answer:0, explain:"<strong>OpenID Connect (OIDC)</strong> is the identity layer built on OAuth 2.0 that adds an ID token conveying authenticated user identity, filling the gap OAuth alone leaves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAML metadata</b>: SAML is a separate SSO standard, and metadata is just its configuration data, not an identity layer over OAuth.</span><span class='qd'><b>RADIUS accounting</b>: RADIUS accounting logs sessions and is unrelated to conveying identity over OAuth.</span><span class='qd'><b>Basic authentication</b>: Basic auth sends credentials directly and does not layer identity onto OAuth.</span>" },
{ id:"D5-047", domain:5, obj:"5.3", diff:"easy", q:"In OpenID Connect, which token specifically conveys claims about the authenticated end user (such as subject and issuer) to the client application?", options:["Access token","Bearer cookie","Refresh token","ID token"], answer:3, explain:"<strong>ID token</strong> is the OIDC artifact, a signed JWT, that carries identity claims like sub and iss to the client, proving who authenticated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Access token</b>: an access token authorizes API calls to resources; it is not guaranteed to convey user identity claims.</span><span class='qd'><b>Refresh token</b>: a refresh token obtains new access tokens and carries no identity claims for the client to read.</span><span class='qd'><b>Bearer cookie</b>: a bearer cookie is a session mechanism, not the OIDC identity token.</span>" },
{ id:"D5-048", domain:5, obj:"5.3", diff:"medium", q:"Two companies establish a trust so employees of company A can access company B's cloud application using company A's directory credentials. This arrangement is BEST described as:", options:["Federated identity management","Local account provisioning","Password synchronization only","Air-gapping"], answer:0, explain:"<strong>Federated identity management</strong> establishes trust between organizations so users authenticate with their home directory and access partner resources without separate accounts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local account provisioning</b>: creating separate local accounts in company B is the opposite of federating existing identities.</span><span class='qd'><b>Password synchronization only</b>: syncing passwords copies credentials rather than establishing federated trust and assertions.</span><span class='qd'><b>Air-gapping</b>: air-gapping isolates systems and would prevent, not enable, cross-company access.</span>" },
{ id:"D5-049", domain:5, obj:"5.3", diff:"easy", q:"In federation terminology, the application that consumes an identity assertion and grants the user access is called the:", options:["Identity provider","Registration authority","Certificate authority","Relying party (service provider)"], answer:3, explain:"<strong>Relying party (service provider)</strong> is the application that trusts and consumes the identity provider's assertion to make an access decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Identity provider</b>: the IdP issues the assertion; it does not consume it.</span><span class='qd'><b>Certificate authority</b>: a CA issues digital certificates, not a party that consumes SSO assertions.</span><span class='qd'><b>Registration authority</b>: an RA vets certificate requests for a CA, unrelated to consuming identity assertions.</span>" },
{ id:"D5-050", domain:5, obj:"5.3", diff:"hard", q:"A security review of a federated SSO deployment finds that the service provider never validates the digital signature on incoming SAML assertions. The MOST serious consequence is that an attacker could:", options:["Only slow the login process","Merely trigger a password reset","Cause harmless XML formatting errors","Forge or tamper with assertions to impersonate any user"], answer:3, explain:"<strong>Forge or tamper with assertions to impersonate any user</strong> is the critical risk: without signature validation, the SP cannot detect a crafted or altered assertion, enabling authentication bypass.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only slow the login process</b>: the impact is a security bypass, not a mere performance issue.</span><span class='qd'><b>Cause harmless XML formatting errors</b>: the danger is impersonation, not cosmetic formatting problems.</span><span class='qd'><b>Merely trigger a password reset</b>: the flaw allows full impersonation, far worse than a reset.</span>" },
{ id:"D5-051", domain:5, obj:"5.3", diff:"medium", q:"An organization wants to reduce the number of separate passwords partners manage while retaining central control at each home organization. Federation delivers this primarily by:", options:["Copying all user accounts into every partner's directory","Sharing one admin password among all partners","Disabling authentication for partners","Letting each user authenticate to their home IdP and passing assertions to partners"], answer:3, explain:"<strong>Letting each user authenticate to their home IdP and passing assertions to partners</strong> is how federation works: identities stay managed at home while trusted assertions grant partner access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copying all user accounts into every partner's directory</b>: duplicating accounts defeats central control and increases sprawl.</span><span class='qd'><b>Disabling authentication for partners</b>: federation still authenticates users; it does not remove authentication.</span><span class='qd'><b>Sharing one admin password among all partners</b>: shared credentials destroy accountability and are insecure.</span>" },
{ id:"D5-052", domain:5, obj:"5.3", diff:"medium", q:"Which protocol, sometimes paired with SAML, is a lightweight XML standard specifically for querying whether a subject is authorized to perform an action on a resource?", options:["XACML","SMTP","SNMP","NTP"], answer:0, explain:"<strong>XACML</strong> (eXtensible Access Control Markup Language) expresses and evaluates fine-grained authorization policies and requests, complementing SAML's authentication assertions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP transports email and has nothing to do with authorization policy.</span><span class='qd'><b>SNMP</b>: SNMP manages network devices, not access-control decisions.</span><span class='qd'><b>NTP</b>: NTP synchronizes time and is unrelated to authorization queries.</span>" },
{ id:"D5-053", domain:5, obj:"5.3", diff:"hard", q:"During an OAuth 2.0 authorization-code flow, an application receives the authorization code and then exchanges it at the token endpoint. Adding PKCE (Proof Key for Code Exchange) primarily protects against:", options:["Weak password hashing","Loss of the refresh token's encryption","Slow token issuance","Interception and replay of the authorization code by a malicious app"], answer:3, explain:"<strong>Interception and replay of the authorization code by a malicious app</strong> is what PKCE prevents: the client proves it initiated the flow via a code verifier, so a stolen authorization code is useless to an attacker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Weak password hashing</b>: PKCE concerns the code exchange, not password storage.</span><span class='qd'><b>Slow token issuance</b>: PKCE is a security measure, not a performance optimization.</span><span class='qd'><b>Loss of the refresh token's encryption</b>: PKCE protects the authorization code exchange, not refresh-token encryption.</span>" },
{ id:"D5-054", domain:5, obj:"5.3", diff:"medium", q:"A partner integration uses SAML for browser SSO but the mobile app team wants a token-based flow better suited to native apps and APIs. The BEST recommendation is to use:", options:["OpenID Connect/OAuth 2.0 for the mobile/API scenario","Only SAML everywhere regardless of client","RADIUS for the mobile app","Kerberos over the public internet"], answer:0, explain:"<strong>OpenID Connect/OAuth 2.0 for the mobile/API scenario</strong> is preferred because its JSON tokens and code flows fit native apps and RESTful APIs better than XML-heavy SAML browser SSO.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only SAML everywhere regardless of client</b>: SAML's redirect/POST browser model is awkward for native mobile and API calls.</span><span class='qd'><b>RADIUS for the mobile app</b>: RADIUS is a network AAA protocol, not an app SSO/API token framework.</span><span class='qd'><b>Kerberos over the public internet</b>: Kerberos is designed for trusted enterprise networks, not internet-facing mobile app federation.</span>" },
{ id:"D5-055", domain:5, obj:"5.3", diff:"easy", q:"'Just-in-time (JIT) provisioning' in federation refers to:", options:["Creating the user's account in the service provider at first successful federated login","Deleting accounts nightly","Encrypting SAML assertions","Rotating certificates hourly"], answer:0, explain:"<strong>Creating the user's account in the service provider at first successful federated login</strong> defines JIT provisioning: the SP builds the local record on demand from assertion attributes rather than pre-creating it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting accounts nightly</b>: this is a deprovisioning routine, not JIT creation at login.</span><span class='qd'><b>Encrypting SAML assertions</b>: assertion encryption is a confidentiality measure, unrelated to on-demand account creation.</span><span class='qd'><b>Rotating certificates hourly</b>: certificate rotation is key management, not provisioning.</span>" },
{ id:"D5-056", domain:5, obj:"5.3", diff:"medium", q:"An OAuth access token is issued with the scope 'read:invoices'. When the client tries to delete an invoice, the API refuses. This refusal demonstrates that OAuth scopes primarily enforce:", options:["Authentication strength","Password complexity","Network segmentation","The limited, delegated authorization granted to the client"], answer:3, explain:"<strong>The limited, delegated authorization granted to the client</strong> is enforced by scopes: the token only permits actions within its granted scope, so a read scope cannot authorize deletion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Authentication strength</b>: scopes govern what may be done, not how strongly the user authenticated.</span><span class='qd'><b>Network segmentation</b>: scopes are logical authorization limits, not network boundaries.</span><span class='qd'><b>Password complexity</b>: scopes are unrelated to password policy.</span>" },
{ id:"D5-057", domain:5, obj:"5.4", diff:"easy", q:"An access-control model in which permissions are assigned to job roles, and users receive permissions by being placed into those roles, is:", options:["Discretionary access control (DAC)","Rule-based access control","Mandatory access control (MAC)","Role-based access control (RBAC)"], answer:3, explain:"<strong>Role-based access control (RBAC)</strong> grants permissions to roles and assigns users to roles, so a user inherits access based on their role rather than individual grants.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary access control (DAC)</b>: DAC lets resource owners grant access at their discretion, not via centrally defined roles.</span><span class='qd'><b>Mandatory access control (MAC)</b>: MAC enforces access via system labels and clearances, not job roles.</span><span class='qd'><b>Rule-based access control</b>: rule-based control uses conditions/ACL rules, not role-to-permission mappings.</span>" },
{ id:"D5-058", domain:5, obj:"5.4", diff:"easy", q:"In which access-control model does the owner of a resource decide who else may access it, for example by setting file permissions they choose?", options:["Mandatory access control (MAC)","Attribute-based access control (ABAC)","Role-based access control (RBAC)","Discretionary access control (DAC)"], answer:3, explain:"<strong>Discretionary access control (DAC)</strong> places access decisions at the discretion of the resource owner, who grants or revokes permissions as they see fit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mandatory access control (MAC)</b>: MAC removes owner discretion; the system enforces labels and clearances.</span><span class='qd'><b>Role-based access control (RBAC)</b>: RBAC assigns access through roles defined centrally, not by individual owners.</span><span class='qd'><b>Attribute-based access control (ABAC)</b>: ABAC decides based on evaluated attributes and policy, not owner discretion.</span>" },
{ id:"D5-059", domain:5, obj:"5.4", diff:"medium", q:"A military system enforces access using data classification labels (e.g., Secret) and user clearances, and no user can override these system-enforced rules. This is characteristic of:", options:["Discretionary access control","Rule-based access control","Role-based access control","Mandatory access control"], answer:3, explain:"<strong>Mandatory access control</strong> enforces access through system-assigned security labels and clearances that users cannot override, typical of classified military environments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary access control</b>: DAC would let owners override or grant access, contradicting the non-overridable enforcement described.</span><span class='qd'><b>Role-based access control</b>: RBAC uses job roles rather than classification labels and clearances.</span><span class='qd'><b>Rule-based access control</b>: rule-based control applies condition rules but is not the label-and-clearance lattice model described.</span>" },
{ id:"D5-060", domain:5, obj:"5.4", diff:"hard", q:"An organization must control access based on real-time context, granting a document only if the user is a manager, in the finance department, on a corporate device, and during business hours. Which model BEST expresses these combined conditions?", options:["DAC","MAC","RBAC","ABAC"], answer:3, explain:"<strong>ABAC</strong> (attribute-based access control) evaluates policies over multiple attributes of the subject, resource, action, and environment (role, department, device, time), making it ideal for this rich contextual rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DAC</b>: owner discretion cannot express dynamic multi-attribute conditions like device and time of day.</span><span class='qd'><b>MAC</b>: MAC uses fixed labels and clearances, not flexible environmental attributes such as business hours.</span><span class='qd'><b>RBAC</b>: role alone (manager) cannot capture department, device, and time constraints without becoming a role explosion.</span>" },
{ id:"D5-061", domain:5, obj:"5.4", diff:"medium", q:"A firewall's access decisions are governed by a set of if-then conditions applied uniformly to all traffic regardless of individual identity, such as 'block port 23 from any source.' This is an example of:", options:["Rule-based access control","Discretionary access control","Role-based access control","Attribute-based access control"], answer:0, explain:"<strong>Rule-based access control</strong> applies predefined conditional rules uniformly to all subjects, exactly like a firewall blocking a port for everyone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discretionary access control</b>: DAC depends on resource owners granting access, not blanket rules.</span><span class='qd'><b>Role-based access control</b>: RBAC ties permissions to user roles, whereas the firewall rule ignores identity.</span><span class='qd'><b>Attribute-based access control</b>: ABAC evaluates many subject/resource attributes; the simple uniform port rule is narrower rule-based control.</span>" },
{ id:"D5-062", domain:5, obj:"5.4", diff:"medium", q:"A rapidly growing company with thousands of employees in defined job functions wants an access model that is simple to administer at scale and maps cleanly to job titles. The BEST choice is:", options:["DAC, letting each manager set permissions","No model; grant access ad hoc","MAC, using classification labels","RBAC, mapping permissions to standardized roles"], answer:3, explain:"<strong>RBAC, mapping permissions to standardized roles</strong> scales well because administrators manage a manageable set of roles tied to job functions rather than thousands of individual grants.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DAC, letting each manager set permissions</b>: distributed owner discretion becomes inconsistent and hard to audit at scale.</span><span class='qd'><b>MAC, using classification labels</b>: MAC's rigid labels fit classified environments, not a commercial job-title structure.</span><span class='qd'><b>No model; grant access ad hoc</b>: ad hoc grants cause privilege sprawl and are unmanageable at scale.</span>" },
{ id:"D5-063", domain:5, obj:"5.4", diff:"hard", q:"A security architect is choosing between RBAC and ABAC. The team needs fine-grained decisions that depend on frequently changing context (location, risk score, resource sensitivity) without creating hundreds of narrowly scoped roles. The architect should choose:", options:["RBAC, because roles can encode every possible context","DAC, because owners understand context best","MAC, because labels change dynamically","ABAC, because policies over attributes avoid role explosion for dynamic conditions"], answer:3, explain:"<strong>ABAC, because policies over attributes avoid role explosion for dynamic conditions</strong> is correct: expressing volatile context as attributes in policy is far more scalable than minting a role for every combination.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RBAC, because roles can encode every possible context</b>: encoding every context as a role produces unmanageable role explosion.</span><span class='qd'><b>MAC, because labels change dynamically</b>: MAC labels are static classifications, not dynamic context signals.</span><span class='qd'><b>DAC, because owners understand context best</b>: owner discretion cannot enforce consistent, dynamic, policy-driven decisions.</span>" },
{ id:"D5-064", domain:5, obj:"5.4", diff:"easy", q:"In access-control matrix terms, the list of permissions associated with a specific object (which subjects can do what to it) is called a(n):", options:["Capability list","Reference monitor","Security kernel","Access control list (ACL)"], answer:3, explain:"<strong>Access control list (ACL)</strong> is the object-centric column of the access matrix, enumerating which subjects hold which rights over that object.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Capability list</b>: a capability list is subject-centric, listing what one subject may access, the row rather than the column.</span><span class='qd'><b>Security kernel</b>: the security kernel implements the reference monitor; it is not a per-object permission list.</span><span class='qd'><b>Reference monitor</b>: the reference monitor is the abstract mediation concept, not a permission list bound to an object.</span>" },
{ id:"D5-065", domain:5, obj:"5.4", diff:"medium", q:"The abstract component that must mediate every access request between subjects and objects, be tamperproof, and be small enough to verify, is the:", options:["Trusted platform module","Reference monitor","Domain controller","Hypervisor"], answer:1, explain:"<strong>Reference monitor</strong> is the concept requiring complete mediation, tamper resistance, and verifiability for all subject-to-object access, implemented by the security kernel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusted platform module</b>: a TPM is a hardware crypto chip, not the access-mediation concept.</span><span class='qd'><b>Domain controller</b>: a domain controller authenticates users in a network domain but is not the abstract mediation model.</span><span class='qd'><b>Hypervisor</b>: a hypervisor manages virtual machines, not the reference-monitor mediation of every access.</span>" },
{ id:"D5-066", domain:5, obj:"5.4", diff:"medium", q:"A MAC-based system prevents a user cleared to Confidential from reading a Secret file. This 'no read up' restriction is the confidentiality rule of which model?", options:["Biba integrity model","Bell-LaPadula model","Clark-Wilson model","Brewer-Nash model"], answer:1, explain:"<strong>Bell-LaPadula model</strong> enforces confidentiality with the simple security property ('no read up'), preventing a subject from reading data above its clearance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Biba integrity model</b>: Biba protects integrity with 'no read down/no write up,' not confidentiality read-up rules.</span><span class='qd'><b>Clark-Wilson model</b>: Clark-Wilson enforces integrity through well-formed transactions, not clearance-based reading.</span><span class='qd'><b>Brewer-Nash model</b>: Brewer-Nash (Chinese Wall) prevents conflicts of interest, not classification read-up.</span>" },
{ id:"D5-067", domain:5, obj:"5.4", diff:"hard", q:"An organization requires that a data-entry clerk can only modify records through approved application transactions, never directly, to preserve integrity. Which model's 'well-formed transaction' and 'separation of duties' principles BEST fit this requirement?", options:["Bell-LaPadula","Biba","Clark-Wilson","Take-Grant"], answer:2, explain:"<strong>Clark-Wilson</strong> enforces integrity by requiring subjects to change data only via certified well-formed transactions and by separating duties, exactly matching the mediated data-entry requirement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bell-LaPadula</b>: Bell-LaPadula addresses confidentiality via clearances, not transaction-mediated integrity.</span><span class='qd'><b>Biba</b>: Biba protects integrity with simple read/write rules but does not center on well-formed transactions and duty separation.</span><span class='qd'><b>Take-Grant</b>: Take-Grant is a theoretical rights-propagation model, not a transaction-integrity control.</span>" },
{ id:"D5-068", domain:5, obj:"5.4", diff:"medium", q:"Under RBAC, a nurse role grants access to patient charts, and Alice is a nurse, so Alice gets that access. If Alice later transfers to billing, the CLEANEST way to adjust her access is to:", options:["Delete every individual permission from Alice one at a time","Remove Alice from the nurse role and add her to the billing role","Change the classification label on all charts","Give Alice discretionary control over charts"], answer:1, explain:"<strong>Remove Alice from the nurse role and add her to the billing role</strong> is the strength of RBAC: reassigning role membership instantly swaps her entire permission set without touching individual grants.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete every individual permission from Alice one at a time</b>: manual per-permission edits defeat RBAC's purpose and invite error.</span><span class='qd'><b>Change the classification label on all charts</b>: relabeling data affects everyone and is a MAC action, not an appropriate way to move one user.</span><span class='qd'><b>Give Alice discretionary control over charts</b>: granting discretion is inappropriate and does not reflect her new job function.</span>" },
{ id:"D5-069", domain:5, obj:"5.4", diff:"easy", q:"Which model is specifically designed to prevent conflicts of interest by blocking a consultant from accessing data of two competing clients?", options:["Bell-LaPadula","Brewer-Nash (Chinese Wall)","Biba","Graham-Denning"], answer:1, explain:"<strong>Brewer-Nash (Chinese Wall)</strong> dynamically restricts access to prevent a subject who accessed one client's data from accessing a competitor's, avoiding conflicts of interest.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bell-LaPadula</b>: Bell-LaPadula governs confidentiality by clearance, not conflict of interest.</span><span class='qd'><b>Biba</b>: Biba addresses data integrity, not competitor data separation.</span><span class='qd'><b>Graham-Denning</b>: Graham-Denning defines rules for creating and managing rights, not conflict-of-interest walls.</span>" },
{ id:"D5-070", domain:5, obj:"5.4", diff:"hard", q:"A hospital wants clinicians to see any patient record in an emergency (override), but wants every such override logged and reviewed. Which access-control approach BEST balances availability of care with accountability?", options:["Rigid MAC that never permits override","Break-glass access with mandatory logging and after-the-fact review","Full DAC letting each clinician grant themselves access","No logging, to speed care"], answer:1, explain:"<strong>Break-glass access with mandatory logging and after-the-fact review</strong> preserves emergency availability while ensuring every override is recorded and audited, balancing care and accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rigid MAC that never permits override</b>: blocking emergency access could harm patients when immediate care is needed.</span><span class='qd'><b>Full DAC letting each clinician grant themselves access</b>: unrestricted self-granting destroys least privilege and accountability.</span><span class='qd'><b>No logging, to speed care</b>: removing logging eliminates the accountability the hospital explicitly requires.</span>" },
{ id:"D5-071", domain:5, obj:"5.4", diff:"medium", q:"In an ABAC policy, 'the requested resource's classification is Restricted' is an example of which attribute type?", options:["Subject attribute","Resource (object) attribute","Environmental attribute","Action attribute"], answer:1, explain:"<strong>Resource (object) attribute</strong> describes a property of the thing being accessed, such as a document's classification of Restricted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Subject attribute</b>: subject attributes describe the requester (role, clearance), not the resource.</span><span class='qd'><b>Environmental attribute</b>: environmental attributes describe context like time or network, not the resource's classification.</span><span class='qd'><b>Action attribute</b>: action attributes describe the operation (read, delete), not the object's sensitivity.</span>" },
{ id:"D5-072", domain:5, obj:"5.4", diff:"medium", q:"A company implements RBAC but discovers roles have quietly accumulated far more permissions than any single job needs, violating least privilege. The BEST corrective process is:", options:["A periodic role/entitlement review to prune excess permissions","Granting all roles administrator rights for simplicity","Switching immediately to DAC","Ignoring it since RBAC is inherently safe"], answer:0, explain:"<strong>A periodic role/entitlement review to prune excess permissions</strong> restores least privilege by regularly examining roles and removing rights that no longer match job needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Granting all roles administrator rights for simplicity</b>: this maximizes over-permissioning, the opposite of the fix.</span><span class='qd'><b>Switching immediately to DAC</b>: DAC does not solve accumulated over-permissioning and worsens central oversight.</span><span class='qd'><b>Ignoring it since RBAC is inherently safe</b>: RBAC is not automatically safe; role bloat still violates least privilege.</span>" },
{ id:"D5-073", domain:5, obj:"5.4", diff:"hard", q:"A defense contractor and a commercial SaaS startup each ask which access model suits them best. The MOST appropriate pairing is:", options:["Contractor: DAC; Startup: MAC","Contractor: MAC; Startup: RBAC","Contractor: RBAC; Startup: MAC","Contractor: DAC; Startup: DAC"], answer:1, explain:"<strong>Contractor: MAC; Startup: RBAC</strong> is best: classified defense work needs the label-and-clearance rigor of MAC, while a commercial startup benefits from RBAC's role-mapped, easily administered access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Contractor: DAC; Startup: MAC</b>: DAC is too permissive for classified data and MAC is overkill and impractical for a startup.</span><span class='qd'><b>Contractor: RBAC; Startup: MAC</b>: RBAC lacks the mandatory clearance enforcement classified work requires, and MAC burdens a startup.</span><span class='qd'><b>Contractor: DAC; Startup: DAC</b>: DAC everywhere fails the contractor's mandatory-control needs and scales poorly for the startup.</span>" },
{ id:"D5-074", domain:5, obj:"5.4", diff:"medium", q:"A capability-based system gives each subject an unforgeable token that itself names the objects the subject may access and the allowed operations. This design is subject-centric, in contrast to:", options:["An object-centric ACL","A password vault","A firewall","A honeypot"], answer:0, explain:"<strong>An object-centric ACL</strong> is the contrast: ACLs bind permissions to each object, whereas capability lists bind permissions to each subject via tokens they carry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A password vault</b>: a vault stores secrets and is not the object-centric permission model contrasted with capabilities.</span><span class='qd'><b>A firewall</b>: a firewall filters network traffic, not the access-matrix representation contrasted here.</span><span class='qd'><b>A honeypot</b>: a honeypot is a decoy, unrelated to the ACL-versus-capability distinction.</span>" },
{ id:"D5-075", domain:5, obj:"5.4", diff:"medium", q:"An organization wants every access decision to be evaluated centrally against written policy rather than scattered in each application's code. Adopting a policy engine that separates the Policy Decision Point from the Policy Enforcement Point is a hallmark of:", options:["DAC","ABAC/policy-based access control","MAC labeling","Password-only authentication"], answer:1, explain:"<strong>ABAC/policy-based access control</strong> centralizes decisions in a Policy Decision Point evaluated against written policy, with enforcement handled by distributed Policy Enforcement Points.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DAC</b>: DAC scatters discretion among owners rather than centralizing policy evaluation.</span><span class='qd'><b>MAC labeling</b>: MAC relies on static labels and clearances, not a centralized attribute-policy engine with PDP/PEP separation.</span><span class='qd'><b>Password-only authentication</b>: this concerns authentication, not the authorization architecture described.</span>" },
{ id:"D5-076", domain:5, obj:"5.4", diff:"easy", q:"Which statement about DAC is TRUE?", options:["The system, not the owner, always makes access decisions","Resource owners can grant access to others at their discretion","It requires security labels on all data","It cannot be used in commercial operating systems"], answer:1, explain:"<strong>Resource owners can grant access to others at their discretion</strong> is the defining trait of DAC, common in commercial file systems where owners set permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The system, not the owner, always makes access decisions</b>: that describes MAC, where the system enforces labels regardless of owner wishes.</span><span class='qd'><b>It requires security labels on all data</b>: mandatory labels are a MAC characteristic, not DAC.</span><span class='qd'><b>It cannot be used in commercial operating systems</b>: DAC is in fact the model most commercial operating systems use.</span>" },
{ id:"D5-077", domain:5, obj:"5.4", diff:"hard", q:"A cloud team enforces that only requests carrying a valid, signed policy attribute of 'project=alpha AND sensitivity<=internal' may read a bucket, evaluated at request time. If a user's project attribute changes, access changes immediately without editing any ACL. This immediate, attribute-driven behavior BEST illustrates the advantage of:", options:["Static ACL maintenance","ABAC's dynamic, policy-evaluated authorization","MAC's fixed clearance lattice","DAC's owner-set permissions"], answer:1, explain:"<strong>ABAC's dynamic, policy-evaluated authorization</strong> is illustrated: because decisions are computed from current attributes at request time, changing an attribute instantly changes access with no ACL edits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static ACL maintenance</b>: static ACLs require manual edits to change access, the opposite of the dynamic behavior shown.</span><span class='qd'><b>MAC's fixed clearance lattice</b>: MAC labels do not flex on arbitrary attributes like project membership in real time.</span><span class='qd'><b>DAC's owner-set permissions</b>: DAC relies on owners manually granting access, not automatic attribute evaluation.</span>" },
{ id:"D5-078", domain:5, obj:"5.4", diff:"medium", q:"Which is the BEST description of the relationship between RBAC and least privilege?", options:["RBAC guarantees least privilege automatically","Well-designed roles help enforce least privilege, but over-broad roles can undermine it","Least privilege is irrelevant to RBAC","RBAC and least privilege are the same thing"], answer:1, explain:"<strong>Well-designed roles help enforce least privilege, but over-broad roles can undermine it</strong> is accurate: RBAC supports least privilege only when roles are scoped tightly, and role bloat erodes that benefit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RBAC guarantees least privilege automatically</b>: poorly designed, over-permissioned roles violate least privilege.</span><span class='qd'><b>Least privilege is irrelevant to RBAC</b>: least privilege is central to designing good roles.</span><span class='qd'><b>RBAC and least privilege are the same thing</b>: RBAC is a model; least privilege is a principle the model can help implement.</span>" },
{ id:"D5-079", domain:5, obj:"5.5", diff:"easy", q:"The overall set of processes for creating, maintaining, and eventually removing a user's digital identity and access over their time with an organization is called the:", options:["Identity and access lifecycle","Data retention schedule","Incident response plan","Change advisory board"], answer:0, explain:"<strong>Identity and access lifecycle</strong> covers provisioning at hire, modification through role changes, and deprovisioning at departure for each user identity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data retention schedule</b>: retention governs how long data is kept, not user identity management.</span><span class='qd'><b>Incident response plan</b>: incident response handles security events, not routine identity lifecycle.</span><span class='qd'><b>Change advisory board</b>: a CAB approves IT changes, not the user identity lifecycle.</span>" },
{ id:"D5-080", domain:5, obj:"5.5", diff:"medium", q:"When a new employee is hired, HR triggers the automatic creation of their accounts and baseline access based on their role. This step of the lifecycle is:", options:["Deprovisioning","Provisioning","Access recertification","Privilege escalation"], answer:1, explain:"<strong>Provisioning</strong> is the creation of accounts and assignment of appropriate initial access when a user joins, ideally automated from an authoritative HR source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deprovisioning</b>: deprovisioning removes access at departure, the opposite of onboarding.</span><span class='qd'><b>Access recertification</b>: recertification is the periodic review of existing access, not initial creation.</span><span class='qd'><b>Privilege escalation</b>: escalation is gaining higher rights, often illicitly, not standard onboarding.</span>" },
{ id:"D5-081", domain:5, obj:"5.5", diff:"medium", q:"An audit finds several accounts still active for employees who left months ago. Which lifecycle failure does this represent, and what is the PRIMARY risk?", options:["Provisioning failure; risk of onboarding delays","Deprovisioning failure; risk of orphaned accounts being abused","Recertification success; no risk","Role explosion; risk of slow logins"], answer:1, explain:"<strong>Deprovisioning failure; risk of orphaned accounts being abused</strong> is correct: access that should have been revoked at termination lingers, and such orphaned accounts are prime targets for misuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Provisioning failure; risk of onboarding delays</b>: this concerns leavers, not new-hire onboarding.</span><span class='qd'><b>Recertification success; no risk</b>: lingering access is a failure, and it clearly poses risk.</span><span class='qd'><b>Role explosion; risk of slow logins</b>: the issue is stale accounts, not too many roles or performance.</span>" },
{ id:"D5-082", domain:5, obj:"5.5", diff:"hard", q:"An employee has moved through three departments in five years, accumulating access from each without any being removed. This condition, and the BEST control to detect and correct it, are:", options:["Privilege creep; periodic access recertification/entitlement review","Data drift; retraining the model","Tailgating; installing a mantrap","Session hijacking; rotating TLS keys"], answer:0, explain:"<strong>Privilege creep; periodic access recertification/entitlement review</strong> is correct: unremoved accumulated rights are privilege creep, and regular recertification detects and prunes access no longer justified.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data drift; retraining the model</b>: data drift is an ML concept unrelated to accumulated user permissions.</span><span class='qd'><b>Tailgating; installing a mantrap</b>: tailgating is a physical entry issue, not accumulated logical access.</span><span class='qd'><b>Session hijacking; rotating TLS keys</b>: session hijacking is a runtime attack, not lifecycle privilege accumulation.</span>" },
{ id:"D5-083", domain:5, obj:"5.5", diff:"medium", q:"Periodically, managers must review and confirm that each of their reports still needs the access they hold, formally attesting to it. This governance activity is called:", options:["Access recertification (attestation)","Penetration testing","Data classification","Key escrow"], answer:0, explain:"<strong>Access recertification (attestation)</strong> is the recurring review in which managers or owners confirm that granted access remains appropriate, revoking what is no longer needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Penetration testing</b>: pen testing probes for vulnerabilities, not confirming user entitlements.</span><span class='qd'><b>Data classification</b>: classification labels data sensitivity, not user access appropriateness.</span><span class='qd'><b>Key escrow</b>: key escrow stores cryptographic keys for recovery, unrelated to access review.</span>" },
{ id:"D5-084", domain:5, obj:"5.5", diff:"easy", q:"Which event should IMMEDIATELY trigger deprovisioning of a user's access?", options:["The user takes a lunch break","The user is terminated or resigns","The user completes annual training","The user changes their desktop wallpaper"], answer:1, explain:"<strong>The user is terminated or resigns</strong> should immediately trigger access removal to prevent post-departure misuse of accounts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The user takes a lunch break</b>: a break does not warrant revoking access.</span><span class='qd'><b>The user completes annual training</b>: completing training is not grounds for deprovisioning.</span><span class='qd'><b>The user changes their desktop wallpaper</b>: a cosmetic change has no bearing on access rights.</span>" },
{ id:"D5-085", domain:5, obj:"5.5", diff:"medium", q:"To reduce the window during which a departing employee retains access, the BEST practice for high-risk terminations is to:", options:["Wait until the monthly review to remove access","Disable access at or before the moment of notification","Leave access until the employee returns their laptop weeks later","Only change the password next quarter"], answer:1, explain:"<strong>Disable access at or before the moment of notification</strong> minimizes the exposure window, ensuring the individual cannot misuse systems once they know they are leaving.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wait until the monthly review to remove access</b>: waiting leaves a long, risky window of active access.</span><span class='qd'><b>Leave access until the employee returns their laptop weeks later</b>: tying access removal to hardware return dangerously delays revocation.</span><span class='qd'><b>Only change the password next quarter</b>: a quarterly change leaves access open far too long.</span>" },
{ id:"D5-086", domain:5, obj:"5.5", diff:"hard", q:"An organization automates joiner-mover-leaver events by connecting its HR system as the authoritative source that drives account creation, role changes, and disablement across all applications. This automation is BEST described as:", options:["Manual ticket-based provisioning","Identity governance with HR-driven automated provisioning/deprovisioning","Ad hoc self-service by users","Static role assignment with no updates"], answer:1, explain:"<strong>Identity governance with HR-driven automated provisioning/deprovisioning</strong> uses the HR system as the system of record to automatically synchronize access across the joiner-mover-leaver lifecycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual ticket-based provisioning</b>: manual tickets are exactly what this automation replaces.</span><span class='qd'><b>Ad hoc self-service by users</b>: user self-service is neither authoritative nor consistent for lifecycle events.</span><span class='qd'><b>Static role assignment with no updates</b>: static assignment fails to reflect movers and leavers.</span>" },
{ id:"D5-087", domain:5, obj:"5.5", diff:"medium", q:"A privileged access management (PAM) system checks out an admin password to an engineer for one hour, records the whole session, and rotates the password afterward. The PRIMARY security benefit is:", options:["Eliminating the need for any admin accounts","Controlling, time-limiting, and auditing privileged use","Making passwords permanent and shared","Removing all logging to protect privacy"], answer:1, explain:"<strong>Controlling, time-limiting, and auditing privileged use</strong> is the core PAM benefit: just-in-time checkout, session recording, and rotation reduce standing privilege and provide accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Eliminating the need for any admin accounts</b>: PAM manages privileged accounts rather than removing the need for them.</span><span class='qd'><b>Making passwords permanent and shared</b>: PAM rotates and individualizes access, not the reverse.</span><span class='qd'><b>Removing all logging to protect privacy</b>: PAM increases logging for accountability, not removes it.</span>" },
{ id:"D5-088", domain:5, obj:"5.5", diff:"medium", q:"During onboarding, a new hire is granted exactly the baseline access of a template that matches their job title, rather than copying a random existing colleague's access. This 'role-based birthright access' approach primarily helps avoid:", options:["Least privilege","Access creep from copying over-permissioned peers","Multifactor authentication","Encryption at rest"], answer:1, explain:"<strong>Access creep from copying over-permissioned peers</strong> is avoided by provisioning from a clean role template, since cloning a colleague can silently propagate their accumulated excess rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege</b>: template-based birthright access supports least privilege rather than being something to avoid.</span><span class='qd'><b>Multifactor authentication</b>: MFA is an authentication control unrelated to how baseline access is templated.</span><span class='qd'><b>Encryption at rest</b>: encryption protects stored data, not access provisioning hygiene.</span>" },
{ id:"D5-089", domain:5, obj:"5.5", diff:"hard", q:"An access review reveals that a database admin also approves their own access requests. Beyond fixing this instance, the BEST systemic control to prevent self-approval of privileged access is to:", options:["Enforce separation of duties in the request/approval workflow","Give the admin more privileges to compensate","Disable the access review process","Let admins approve all their own requests for speed"], answer:0, explain:"<strong>Enforce separation of duties in the request/approval workflow</strong> systemically prevents self-approval by requiring a different, independent party to authorize privileged access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give the admin more privileges to compensate</b>: adding privileges worsens the concentration of power.</span><span class='qd'><b>Disable the access review process</b>: removing reviews eliminates the very control that surfaced the problem.</span><span class='qd'><b>Let admins approve all their own requests for speed</b>: institutionalizing self-approval is exactly the risk to eliminate.</span>" },
{ id:"D5-090", domain:5, obj:"5.5", diff:"medium", q:"An identity governance metric tracks the average time between an employee's termination and the revocation of all their access. Keeping this metric near zero primarily reduces the risk of:", options:["Slow application performance","Post-employment unauthorized access via lingering accounts","Excessive storage costs","Poor data visualization"], answer:1, explain:"<strong>Post-employment unauthorized access via lingering accounts</strong> is the risk minimized by fast revocation, closing the window in which a former employee's credentials remain usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slow application performance</b>: revocation speed is a security metric, not a performance one.</span><span class='qd'><b>Excessive storage costs</b>: storage cost is unrelated to how quickly access is revoked.</span><span class='qd'><b>Poor data visualization</b>: this metric concerns access risk, not dashboards.</span>" },
{ id:"D5-091", domain:5, obj:"5.6", diff:"easy", q:"Which network AAA protocol, commonly used to authenticate remote and wireless users, encrypts only the password in its access-request and runs over UDP?", options:["RADIUS","TACACS+","Kerberos","SAML"], answer:0, explain:"<strong>RADIUS</strong> uses UDP and, in its original design, encrypts only the user password within the access-request while leaving other attributes exposed, making it common for remote and Wi-Fi authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TACACS+</b>: TACACS+ runs over TCP and encrypts the entire payload, not just the password.</span><span class='qd'><b>Kerberos</b>: Kerberos is a ticket-based authentication protocol, not a RADIUS-style network AAA server for dial-in/Wi-Fi.</span><span class='qd'><b>SAML</b>: SAML is a web SSO assertion standard, not a network access AAA protocol.</span>" },
{ id:"D5-092", domain:5, obj:"5.6", diff:"medium", q:"A network team needs granular command-level authorization and full-payload encryption for administering Cisco devices, separating authentication, authorization, and accounting. Which protocol BEST fits?", options:["RADIUS","TACACS+","LDAP","HTTP Basic"], answer:1, explain:"<strong>TACACS+</strong> separates AAA into independent functions, supports per-command authorization, runs over TCP, and encrypts the entire packet, ideal for device administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RADIUS</b>: RADIUS combines authentication and authorization and encrypts only the password, offering weaker command-level control.</span><span class='qd'><b>LDAP</b>: LDAP is a directory protocol, not a device AAA protocol with command authorization.</span><span class='qd'><b>HTTP Basic</b>: HTTP Basic just sends credentials and provides no AAA separation or command authorization.</span>" },
{ id:"D5-093", domain:5, obj:"5.6", diff:"easy", q:"In Kerberos, which component issues the initial Ticket-Granting Ticket (TGT) after a user authenticates?", options:["The Ticket-Granting Service (TGS)","The Authentication Service (AS) of the KDC","The application server","The relying party"], answer:1, explain:"<strong>The Authentication Service (AS) of the KDC</strong> validates the user's initial authentication and issues the TGT that the client later presents to obtain service tickets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The Ticket-Granting Service (TGS)</b>: the TGS issues service tickets in exchange for a valid TGT; it does not issue the initial TGT.</span><span class='qd'><b>The application server</b>: the application server accepts a service ticket; it does not issue TGTs.</span><span class='qd'><b>The relying party</b>: relying party is federation terminology, not a Kerberos KDC component.</span>" },
{ id:"D5-094", domain:5, obj:"5.6", diff:"medium", q:"In the Kerberos flow, after the client holds a TGT and wants to reach a specific file server, it presents the TGT to the TGS to obtain a:", options:["New TGT","Service ticket for that file server","RADIUS accounting record","SAML assertion"], answer:1, explain:"<strong>Service ticket for that file server</strong> is what the TGS returns when the client presents its TGT, authorizing access to that particular service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>New TGT</b>: the TGS grants service tickets, not additional TGTs, from a presented TGT.</span><span class='qd'><b>RADIUS accounting record</b>: RADIUS accounting is unrelated to Kerberos ticket exchange.</span><span class='qd'><b>SAML assertion</b>: SAML assertions belong to web federation, not Kerberos.</span>" },
{ id:"D5-095", domain:5, obj:"5.6", diff:"hard", q:"A CISSP candidate must order the Kerberos exchange correctly. Which sequence is right?", options:["Client gets service ticket from AS, then TGT from TGS, then accesses service","Client authenticates to AS and gets TGT, presents TGT to TGS for a service ticket, then presents the service ticket to the target service","Client presents password directly to the file server, which validates it","Client gets a SAML assertion from the KDC, then a TGT"], answer:1, explain:"<strong>Client authenticates to AS and gets TGT, presents TGT to TGS for a service ticket, then presents the service ticket to the target service</strong> is the correct Kerberos order: AS then TGS then service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Client gets service ticket from AS, then TGT from TGS, then accesses service</b>: this reverses the roles; the AS issues the TGT and the TGS issues service tickets.</span><span class='qd'><b>Client presents password directly to the file server, which validates it</b>: Kerberos avoids sending passwords to services; tickets are used instead.</span><span class='qd'><b>Client gets a SAML assertion from the KDC, then a TGT</b>: SAML is not part of Kerberos, and the KDC issues tickets, not assertions.</span>" },
{ id:"D5-096", domain:5, obj:"5.6", diff:"hard", q:"A security architect notes that Kerberos relies heavily on time synchronization and a central KDC. Two consequences the design must account for are:", options:["Clock skew can cause ticket rejection, and the KDC is a single point of failure needing redundancy","Kerberos needs no time sync and has no central dependency","Tickets never expire, so time is irrelevant","The KDC is optional in all deployments"], answer:0, explain:"<strong>Clock skew can cause ticket rejection, and the KDC is a single point of failure needing redundancy</strong> captures two real design concerns: timestamps guard against replay so skew breaks tickets, and the KDC's centrality demands high availability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Kerberos needs no time sync and has no central dependency</b>: Kerberos explicitly depends on synchronized clocks and a central KDC.</span><span class='qd'><b>Tickets never expire, so time is irrelevant</b>: Kerberos tickets carry lifetimes and timestamps, so time is very relevant.</span><span class='qd'><b>The KDC is optional in all deployments</b>: the KDC is the core of Kerberos, not optional.</span>" },
{ id:"D5-097", domain:5, obj:"5.6", diff:"medium", q:"A primary security advantage of Kerberos over sending reusable passwords across the network is that it:", options:["Transmits the user's password to every service in cleartext","Uses time-limited tickets and symmetric keys so the password is not sent to each service","Requires no authentication server","Relies entirely on public web federation"], answer:1, explain:"<strong>Uses time-limited tickets and symmetric keys so the password is not sent to each service</strong> is Kerberos's advantage: services are accessed with tickets, keeping the long-term password off the wire and limiting replay.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Transmits the user's password to every service in cleartext</b>: Kerberos is designed specifically to avoid sending passwords to services.</span><span class='qd'><b>Requires no authentication server</b>: Kerberos centers on the KDC's Authentication Service.</span><span class='qd'><b>Relies entirely on public web federation</b>: Kerberos is an enterprise protocol, not web federation.</span>" },
{ id:"D5-098", domain:5, obj:"5.6", diff:"medium", q:"An enterprise uses 802.1X for wired port authentication, with switches acting as authenticators that forward credentials to a central server for validation. That central validation server most commonly speaks which protocol?", options:["RADIUS","SMTP","FTP","ICMP"], answer:0, explain:"<strong>RADIUS</strong> is the standard back-end AAA protocol an 802.1X authenticator uses to validate supplicant credentials against a central authentication server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SMTP</b>: SMTP delivers email and has no role in 802.1X authentication.</span><span class='qd'><b>FTP</b>: FTP transfers files and is not an AAA validation protocol.</span><span class='qd'><b>ICMP</b>: ICMP handles diagnostic messages like ping, not authentication.</span>" },
{ id:"D5-099", domain:5, obj:"5.6", diff:"medium", q:"When comparing RADIUS and TACACS+, which statement is accurate?", options:["RADIUS uses TCP and encrypts everything; TACACS+ uses UDP and encrypts only the password","RADIUS uses UDP and encrypts only the password; TACACS+ uses TCP and encrypts the full payload","Both use UDP and neither encrypts anything","Both are XML web-SSO protocols"], answer:1, explain:"<strong>RADIUS uses UDP and encrypts only the password; TACACS+ uses TCP and encrypts the full payload</strong> correctly contrasts the two, which is why TACACS+ is favored for granular, secure device administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RADIUS uses TCP and encrypts everything; TACACS+ uses UDP and encrypts only the password</b>: this reverses their actual transport and encryption behavior.</span><span class='qd'><b>Both use UDP and neither encrypts anything</b>: TACACS+ uses TCP and both encrypt at least the password.</span><span class='qd'><b>Both are XML web-SSO protocols</b>: they are network AAA protocols, not XML SSO standards.</span>" },
{ id:"D5-100", domain:5, obj:"5.6", diff:"hard", q:"An organization wants centralized authentication for its VPN, wireless, and network devices, plus per-command authorization on routers. The BEST architecture pairs:", options:["RADIUS for network-access AAA (VPN/Wi-Fi) and TACACS+ for device administration authorization","TACACS+ for Wi-Fi only and RADIUS for nothing","Kerberos for VPN and SAML for router commands","LDAP for command authorization and SMTP for Wi-Fi"], answer:0, explain:"<strong>RADIUS for network-access AAA (VPN/Wi-Fi) and TACACS+ for device administration authorization</strong> plays to each protocol's strengths: RADIUS excels at broad network access, while TACACS+ provides granular per-command control on network devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TACACS+ for Wi-Fi only and RADIUS for nothing</b>: this ignores RADIUS's core strength for VPN/Wi-Fi access authentication.</span><span class='qd'><b>Kerberos for VPN and SAML for router commands</b>: Kerberos and SAML are not designed for VPN access AAA or per-command router authorization.</span><span class='qd'><b>LDAP for command authorization and SMTP for Wi-Fi</b>: LDAP is a directory protocol and SMTP is email; neither performs these AAA roles.</span>" }
);
